const assert = require('assert');
const LifecycleManager = require('../../../src/core/LifecycleManager');
const DiContainer = require('../../../src/core/DiContainer');

describe('LifecycleManager (Integration)', () => {
  before(() => DiContainer.reset());

  it('should initialize multiple services', () => {
    class A {}
    class B {}

    const registry = new Map();
    registry.set('A', A);
    registry.set('B', B);

    LifecycleManager.initializeAll(registry);

    assert.ok(DiContainer.resolve('A') instanceof A);
    assert.ok(DiContainer.resolve('B') instanceof B);
  });
});